def verify(answer):
    # If N ≡ 7 (mod 8), then N = 8k + 7 for some integer k
    # N mod 4 = (8k + 7) mod 4 = 0 + 3 = 3
    # So the answer must be 3
    try:
        val = int(str(answer).strip())
        # Check: for any N ≡ 7 (mod 8), N mod 4 should equal val
        for k in range(100):
            N = 8 * k + 7
            if N % 4 != val:
                return False
        return True
    except Exception:
        return False

def verify(answer):
    try:
        ans = str(answer).strip().lower()
        if ans not in ("odd", "even", "neither"):
            return False

        from sympy import symbols, Function, simplify

        x = symbols('x')

        # Test with specific even and odd functions
        # f(x) = x^2 (even), g(x) = x^3 (odd)
        # f(g(x^3)) = f((x^3)^3) = f(x^9) = (x^9)^2 = x^18
        # x^18 is even function

        # Let's verify with multiple examples
        test_cases = [
            # (f, g) where f is even and g is odd
            (lambda t: t**2, lambda t: t**3),       # f(g(x^3)) = (x^9)^2 = x^18, even
            (lambda t: t**4, lambda t: t),            # f(g(x^3)) = (x^3)^4 = x^12, even
            (lambda t: t**2 + 1, lambda t: t**3),    # f(g(x^3)) = x^18 + 1, even
            (lambda t: t**2, lambda t: t**5),         # f(g(x^3)) = (x^15)^2 = x^30, even
        ]

        results = set()
        import numpy as np
        test_vals = [0.5, 1.0, 1.5, 2.0]

        for f_func, g_func in test_cases:
            is_even = True
            is_odd = True
            for xv in test_vals:
                pos = f_func(g_func(xv**3))
                neg = f_func(g_func((-xv)**3))
                if abs(pos - neg) > 1e-9:
                    is_even = False
                if abs(pos + neg) > 1e-9:
                    is_odd = False

            if is_even and not is_odd:
                results.add("even")
            elif is_odd and not is_even:
                results.add("odd")
            else:
                results.add("neither")

        # All test cases should agree
        if len(results) == 1:
            computed = results.pop()
            return ans == computed
        else:
            return False

    except Exception:
        return False

