def verify(answer):
    from sympy import Rational, sqrt, simplify, Symbol, solve

    x = Symbol('x')
    poly = x**2 + 2*x - 15
    roots = solve(poly, x)

    values = []
    for r in roots:
        denom = r**5 + r**4 - r**3 - r**2
        if denom != 0:
            val = (r**3 - 1) / denom
            val = simplify(val)
            values.append(val)

    greatest = max(values, key=lambda v: float(v))

    try:
