def verify(answer):
    from fractions import Fraction
    try:
        # Parse the candidate answer
        candidate = Fraction(str(answer).strip())
    except Exception:
        try:
            candidate = Fraction(float(str(answer).strip())).limit_denominator(10000)
        except Exception:
            return False

    # Compute partial sum using exact rational arithmetic
    total = Fraction(0)
    N = 10000
    for k in range(2, N + 1):
        term = Fraction(k - 3, k * (k**2 - 1))
        total += term

    # The tail sum for k > N should be small; check that candidate is close
    # Use a tolerance approach with Fraction comparison
    # Estimate tail: roughly sum_{k=N}^inf (k-3)/(k^3) ~ integral ~ 1/(2N^2) ~ tiny
    # For N=10000, tail < 1/N^2 = 1e-8

    diff = abs(candidate - total)
    # Allow tolerance of 1e-6 (much larger than tail)
    return diff < Fraction(1, 1000000)

