            # Multiple combinations exist - check if they all give same product
            # or if answer is in the set
            return ans in valid_products
    except Exception:
        return False

def verify(answer):
    try:
        ans = int(str(answer).strip())
    except Exception:
        return False

    representable = set()

    # Case 1: x is a positive integer k, expression = 2k^2
    k = 1
    while 2 * k * k <= 2025:
        representable.add(2 * k * k)
        k += 1

    # Case 2: x in (n, n+1) for integer n >= 0, expression = x*(2n+1)
    # x*(2n+1) ranges over open interval (n*(2n+1), (n+1)*(2n+1))
    # integers strictly between n*(2n+1) and (n+1)*(2n+1)
    n = 0
    while True:
        low = n * (2 * n + 1)
        high = (n + 1) * (2 * n + 1)
        if low >= 2025:
            break
        for m in range(low + 1, min(high, 2026)):
            representable.add(m)
        n += 1

    count = 0
    for m in range(1, 2026):
        if m not in representable:
            count += 1

    return ans == count
